import{_ as a,o as r,c as t,a3 as l}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"154. Interpreter Allowances","description":"","frontmatter":{"title":"154. Interpreter Allowances","eba":"Mental Health Services 2024-2028","topics":["allowances","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/154-interpreter-allowances.md","filePath":"ebas/mental-health/support-services/preliminary/154-interpreter-allowances.md"}'),n={name:"ebas/mental-health/support-services/preliminary/154-interpreter-allowances.md"};function s(o,e,i,p,c,h){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="_154-interpreter-allowances" tabindex="-1">154. Interpreter Allowances <a class="header-anchor" href="#_154-interpreter-allowances" aria-label="Permalink to &quot;154. Interpreter Allowances&quot;">​</a></h1><p><strong>154.1</strong> Any person employed as a qualified interpreter/translator and who is accredited by the National Accreditation Authority for Translators and Interpreters (NAATI) shall be paid an Interpreter Allowance per week pursuant to <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>154.2</strong> The amount payable per week under clause 154.1above is dependent upon the Employee’s level of accreditation by NAATI and their years of experience.</p><p><strong>154.3</strong> The Interpreter Allowances shall be additional to any other allowance to which the Employee is entitled under Section 4 and shall be considered part of the normal weekly rate of pay for all purposes.</p><p><strong>154.4</strong> Employees who are eligible for payment of the Interpreter Allowances shall be ineligible for the experience payments in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p>',5)])])}const u=a(n,[["render",s]]);export{m as __pageData,u as default};
